// ==UserScript==
// @name           Update SN Favicon
// @version        0.3
// @description    Replaces SN icon with something almost like the old one but much uglier.
// @match        https://vu.service-now.com/*
// @match        https://services.vu.nl/*
// ==/UserScript==
window.addEventListener('load', function() {
    var favicon = document.querySelector('link[rel~="icon"]');
    var clone = favicon.cloneNode(!0);
   // Boudewijn icon
    clone.href = "data:image/png;base64,";
    // pot hak geen achtergrond
    //one.href = "data:image/png;base64,";
    // template clone.href = "";
    favicon.parentNode.removeChild(favicon);
    document.head.appendChild(clone);
}, false);
